SELECT

FROM write_off t0 left join project_info t2 on t0.project_id = t2.id and t2.is_deleted = 0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.write_off_date BETWEEN

      #{item}



    AND (t2.affiliated_org IN
    #{item}

    OR

      t2.manage LIKE CONCAT('%',#{item},'%')

    )


    AND t0.id = #{request.id}


    AND t0.write_off_status = #{request.writeOffStatus}


    AND t2.project_state in

      #{item}



    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.project_name LIKE CONCAT ('%',#{request.projectName},'%')


    AND t0.project_id = #{request.projectId}


    AND t0.compensation_amount = #{request.compensationAmount}


    AND t0.compensation_date = #{request.compensationDate}


    AND t0.write_dff_amount = #{request.writeDffAmount}


    AND t0.write_off_date = #{request.writeOffDate}


    AND t0.write_off_classification = #{request.writeOffClassification}


    AND t0.total_collection_amount = #{request.totalCollectionAmount}


    AND t0.remarks = #{request.remarks}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
